const GCD=2.5,SLOTS=32;
const skills=[
{id:'split',name:'热分裂弹',type:'gcd',recast:2.5,heat:5,battery:0,icon:'✹',color:'#f7a21b'}, {id:'slug',name:'热独头弹',type:'gcd',recast:2.5,heat:5,battery:0,icon:'✦',color:'#5b8cff'}, {id:'clean',name:'热狙击弹',type:'gcd',recast:2.5,heat:5,battery:10,icon:'✧',color:'#6f54d9'},
{id:'drill',name:'钻头',type:'gcd',recast:2.5,cd:20,icon:'✺',color:'#ff9a24'}, {id:'air',name:'空气锚',type:'gcd',recast:2.5,cd:40,battery:20,icon:'⚓',color:'#2d63c8'}, {id:'saw',name:'回转飞锯',type:'gcd',recast:2.5,cd:60,battery:20,icon:'◎',color:'#e1392d'}, {id:'blast',name:'烈焰弹',type:'gcd',recast:1.5,icon:'◉',color:'#ff4b25',note:'过热时常用，1.5s GCD'}, {id:'fmf',name:'全金属爆发',type:'gcd',recast:2.5,cd:120,icon:'▣',color:'#31a9c9'},
{id:'double',name:'双将',type:'ogcd',cd:1,charges:3,icon:'☷',color:'#4198ff'}, {id:'check',name:'将死',type:'ogcd',cd:1,charges:3,icon:'☶',color:'#8b63d8'}, {id:'reassemble',name:'整备',type:'ogcd',cd:55,charges:2,icon:'✚',color:'#a855f7'}, {id:'barrel',name:'枪管加热',type:'ogcd',cd:120,heat:50,icon:'♨',color:'#00a6d6'}, {id:'hyper',name:'超荷',type:'ogcd',cd:10,heat:-50,icon:'🔥',color:'#ef4444'}, {id:'wildfire',name:'野火',type:'ogcd',cd:120,icon:'⏱',color:'#c0392b'}, {id:'queen',name:'后式自走人偶',type:'ogcd',cd:6,battery:-50,icon:'♛',color:'#13a89e'}, {id:'tactician',name:'策动',type:'ogcd',cd:90,icon:'▰',color:'#f59e0b'}];
const byId=Object.fromEntries(skills.map(s=>[s.id,s])); let plan=Array.from({length:SLOTS},()=>({gcd:null,ogcds:[null,null,null]})); let state=[]; const $=id=>document.getElementById(id), timeOf=i=>i*GCD;
function style(s){return `background:linear-gradient(135deg,${s.color},#111827);border-color:${s.color}`}
function derive(){let heat=0,battery=0,double=3,check=3; state=plan.map(c=>{[c.gcd,...c.ogcds].filter(Boolean).forEach(id=>{const s=byId[id];heat=Math.max(0,Math.min(100,heat+(s.heat||0)));battery=Math.max(0,Math.min(100,battery+(s.battery||0)));if(id==='double')double--;if(id==='check')check--;});return{heat,battery,double:Math.max(0,double),check:Math.max(0,check)}})}
function avail(s,slot){const now=timeOf(slot),uses=[];plan.forEach((c,i)=>[c.gcd,...c.ogcds].forEach(id=>id===s.id&&uses.push(timeOf(i)))); if(!uses.length)return{ok:true}; const cd=s.cd||s.recast||2.5, charges=s.charges||1; if(s.charges){const recent=uses.filter(t=>now-t<cd);return{ok:recent.length<charges,msg:`充能中，约 ${Math.ceil(cd-(now-recent[0]))}s 后`}} const last=Math.max(...uses);return{ok:now-last>=cd,msg:`CD中，约 ${Math.ceil(cd-(now-last))}s 后`}}
function render(){derive(); const last=state.at(-1)||{heat:0,battery:0,double:3,check:3}; $('heatNow').textContent=last.heat;$('batNow').textContent=last.battery;$('doubleNow').textContent=last.double;$('checkNow').textContent=last.check;$('heatMeter').value=last.heat;$('batMeter').value=last.battery; $('grid').innerHTML=''; plan.forEach((c,i)=>{const col=document.createElement('div');col.className='col';col.innerHTML=`<div class="time">${timeOf(i)}s</div><div class="bars"><i class="heat" style="height:${state[i].heat}%"></i><i class="bat" style="height:${state[i].battery}%"></i></div>`; col.append(slot(i,'gcd',null,c.gcd)); [0,1,2].forEach(j=>col.append(slot(i,'ogcd',j,c.ogcds[j]))); $('grid').append(col)})}
function slot(i,kind,j,id){const el=document.createElement('div');el.className='slot '+(kind==='gcd'?'big':'');el.ondragover=e=>e.preventDefault();el.ondrop=e=>drop(e,i,kind,j); if(id){const s=byId[id];el.innerHTML=`<span class="placed ${s.recast===1.5?'short':''}" style="${style(s)}" title="点击移除">${s.icon}</span>`;el.onclick=()=>{kind==='gcd'?plan[i].gcd=null:plan[i].ogcds[j]=null;render()}} return el}
function drop(e,slot,kind,j){e.preventDefault();const s=byId[e.dataTransfer.getData('skill')]; if(!s)return; if(kind!==s.type)return toast(kind==='gcd'?'这里只能放GCD战技。':'GCD之间最多三个小格用于能力技。'); const a=avail(s,slot); if(!a.ok)return toast(`${s.name} ${a.msg}，不能放在 ${timeOf(slot).toFixed(1)}s。`); const prev=state[slot-1]||{heat:0,battery:0}; if((s.heat||0)<0&&prev.heat<Math.abs(s.heat))return toast(`${s.name} 需要 ${Math.abs(s.heat)} 热量。`); if((s.battery||0)<0&&prev.battery<Math.abs(s.battery))return toast(`${s.name} 需要 ${Math.abs(s.battery)} 电量。`); kind==='gcd'?plan[slot].gcd=s.id:plan[slot].ogcds[j]=s.id; toast(`${s.name} 已放入 ${timeOf(slot).toFixed(1)}s。`); render()}
function toast(t){$('toast').textContent=t}
$('palette').innerHTML=skills.map(s=>`<div class="skill ${s.type}" draggable="true" data-id="${s.id}" title="${s.name}｜${s.type.toUpperCase()}｜CD ${s.cd||s.recast||0}s${s.note?'｜'+s.note:''}"><span style="${style(s)}">${s.icon}</span><small>${s.name}</small></div>`).join(''); document.querySelectorAll('.skill').forEach(el=>el.ondragstart=e=>e.dataTransfer.setData('skill',el.dataset.id)); $('reset').onclick=()=>{plan=Array.from({length:SLOTS},()=>({gcd:null,ogcds:[null,null,null]}));render();toast('已重置。')}; render();
